.site-in-edit-mode .hero-gradient-canvas-wrapper { max-height:1000px!important; }

.marketplaceapppage .hero__image img { max-height: 200px; }

.hero-gradient-container .button { white-space: normal !important; }

.hero-gradient-container .home-hero__wrapper { position: relative; }

.hero-gradient-container .hero-gradient-canvas-wrapper { position: absolute;
    top: 0;
    height: 100%;
   width: 100%; }

.hero-gradient-container .home-hero__shapes-container { aspect-ratio: 1/1; }

.hero .text-left .icon-block { margin-right: 0; margin-top: 0; }

.hero-pb { padding-bottom:max(170px,6vw) }

@keyframes background {
0%,to{background-position:0% 50%}50%{background-position:100% 50%}
}

@keyframes pulse {
50%{opacity:.5}
}

@keyframes loading {
0%{transform:rotate(0)}to{transform:rotate(360deg)}
}

@keyframes animation-floating {
0%{transform:translate(0)}50%{transform:translateY(8px)}to{transform:translate(0)}
}

.animate-background { animation:background 7s ease infinite }

.animate-pulse { animation:pulse 2s cubic-bezier(.4,0,.6,1) infinite }

.img-aspect-ratio:after { content:"";position:absolute;z-index:0;top:50%;left:50%;width:50px;height:50px;margin-top:-30px;margin-left:-30px;border:5px solid var(--heather);border-top-color:var(--fiord);border-radius:50px;animation:loading 2s linear infinite }

.animation--floating { animation-name:animation-floating;animation-duration:3s;animation-timing-function:ease-in-out;animation-iteration-count:infinite }

.home-hero .gradient-container { position:absolute;top:0;left:0;opacity:.8;height:100%;width:100%;pointer-events:none }

.home-hero .gradient-container.gradient-container--is-hovered { opacity:.3 }

.aspect-video.rounded-3xl.bg-vulcan-85\/10 { overflow: hidden; }

.pointer-events-none.fixed.right-0.top-0.z-50.w-full.bg-purple-20-shade\/40.pb-4.pt-4.transition-all.lg\:pt-8 { background: none; }

.opticon2025page .relative.z-50.flex.items-center.justify-center.gap-6.border-b-2.bg-black\/80.px-10.py-2\.5.shadow-\[0px_0px_20px_0px_rgba\(25\,75\,255\,0\.30\)\].border-optimizely-blue { display: none !important; }

.not-rte.rounded.border.hover\:shadow-card-hover.focus\:shadow-card-hover.mx-auto.max-w-5xl > .rounded.bg-vulcan { height: 100%; }

.bg-select-wrapper:has(.form-list.show) { overflow: auto !important; }

