@supports (animation-timeline: view()) {
  .scroll-reveal-item {
    animation: scrollReveal linear both;
    animation-timeline: view();
    animation-range: entry 0% entry 100%;
    opacity: 0;
    transform: translateY({{translateDistance}});
  }
