components.js_init:
(function(){
  document.querySelectorAll('[data-magnetic]').forEach(wrap => {
    const btn = wrap.querySelector('.magnetic-btn');
    const strength = parseFloat(wrap.dataset.strength) || 0.3;
    let rect, animId;
    wrap.addEventListener('mouseenter', () => { rect = wrap.getBoundingClientRect(); });
    wrap.addEventListener('mousemove', (e) => {
      if (!rect) rect = wrap.getBoundingClientRect();
      const x = e.clientX - rect.left - rect.width / 2;
      const y = e.clientY - rect.top - rect.height / 2;
      btn.style.transform = `translate(${x * strength}px, ${y * strength}px)`;
      btn.style.setProperty('--mx', ((e.clientX - rect.left) / rect.width * 100) + '%');
      btn.style.setProperty('--my', ((e.clientY - rect.top) / rect.height * 100) + '%');
    });
    wrap.addEventListener('mouseleave', () => {
      btn.style.transform = 'translate(0, 0)';
      btn.style.transition = 'transform 0.5s cubic-bezier(0.34, 1.56, 0.64, 1), background 0.3s, box-shadow 0.3s';
      setTimeout(() => {
        btn.style.transition = 'transform 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94), background 0.3s, box-shadow 0.3s';
      }, 500);
    });
  });
})();

