components.css:
.text-scramble {
  font-family: {{fontFamily}};
  font-size: {{fontSize}};
  font-weight: {{fontWeight}};
  color: {{textColor}};
  letter-spacing: {{letterSpacing}};
  min-height: 1.2em;
  display: inline-block;
}
.text-scramble .char-scrambling {
  color: {{scrambleColor}};
  opacity: 0.7;
}

components.js_init:
(function(){
  const chars = '{{charSet}}';
  class TextScramble {
    constructor(el) {
      this.el = el;
      this.text = el.dataset.text;
      this.queue = [];
      this.frame = 0;
      this.running = false;
    }
    scramble() {
      if (this.running) return;
      this.running = true;
      const oldText = this.el.textContent;
      const newText = this.text;
      const length = Math.max(oldText.length, newText.length);
      this.queue = [];
      for (let i = 0; i < length; i++) {
        const from = oldText[i] || '';
        const to = newText[i] || '';
        const start = Math.floor(Math.random() * 20);
        const end = start + Math.floor(Math.random() * 20) + 10;
        this.queue.push({ from, to, start, end });
      }
      this.frame = 0;
      this.update();
    }
    update() {
      let output = '';
      let complete = 0;
      for (let i = 0; i < this.queue.length; i++) {
        let { from, to, start, end, char } = this.queue[i];
        if (this.frame >= end) {
          complete++;
          output += to;
        } else if (this.frame >= start) {
          if (!char || Math.random() < 0.28) {
            char = chars[Math.floor(Math.random() * chars.length)];
            this.queue[i].char = char;
          }
          output += '<span class="char-scrambling">' + char + '</span>';
        } else {
          output += from;
        }
      }
      this.el.innerHTML = output;
      if (complete < this.queue.length) {
        requestAnimationFrame(() => this.update());
        this.frame++;
      } else {
        this.running = false;
      }
    }
  }
  document.querySelectorAll('[data-scramble]').forEach(el => {
    const scrambler = new TextScramble(el);
    const trigger = el.dataset.trigger || 'scroll';
    if (trigger === 'load') {
      scrambler.scramble();
    } else if (trigger === 'hover') {
      el.addEventListener('mouseenter', () => scrambler.scramble());
    } else {
      const obs = new IntersectionObserver(entries => {
        entries.forEach(entry => {
          if (entry.isIntersecting) { scrambler.scramble(); obs.unobserve(entry.target); }
        });
      }, { threshold: 0.5 });
      obs.observe(el);
    }
  });
})();

