(function(){
  document.querySelectorAll('[data-tilt]').forEach(card => {
    const max = parseFloat(card.dataset.max) || 15;
    const wrap = card.parentElement;
    wrap.addEventListener('mousemove', (e) => {
      const rect = wrap.getBoundingClientRect();
      const x = (e.clientX - rect.left) / rect.width;
      const y = (e.clientY - rect.top) / rect.height;
      const rotateX = (0.5 - y) * max;
      const rotateY = (x - 0.5) * max;
      card.style.transform = `rotateX(${rotateX}deg) rotateY(${rotateY}deg)`;
      const shine = (x * 200) - 100;
      card.style.setProperty('--shine', shine + '%');
    });
    wrap.addEventListener('mouseleave', () => {
      card.style.transition = 'transform 0.6s cubic-bezier(0.34, 1.56, 0.64, 1), box-shadow 0.3s';
      card.style.transform = 'rotateX(0) rotateY(0)';
      setTimeout(() => { card.style.transition = 'transform 0.15s ease-out, box-shadow 0.3s'; }, 600);
    });
  });
})();

