components.js_init:
(function(){
  document.querySelectorAll('[data-typewriter]').forEach(el => {
    const strings = JSON.parse(el.dataset.strings || '["Hello World"]');
    const speed = parseInt(el.dataset.speed) || 80;
    const pause = parseInt(el.dataset.pause) || 2000;
    const delSpeed = parseInt(el.dataset.deleteSpeed) || 40;
    let strIdx = 0, charIdx = 0, isDeleting = false;
    function tick() {
      const current = strings[strIdx % strings.length];
      if (isDeleting) {
        el.textContent = current.substring(0, charIdx - 1);
        charIdx--;
        if (charIdx === 0) {
          isDeleting = false;
          strIdx++;
          setTimeout(tick, 400);
          return;
        }
        setTimeout(tick, delSpeed);
      } else {
        el.textContent = current.substring(0, charIdx + 1);
        charIdx++;
        if (charIdx === current.length) {
          if (strings.length > 1) {
            isDeleting = true;
            setTimeout(tick, pause);
          }
          return;
        }
        setTimeout(tick, speed + Math.random() * 40 - 20);
      }
    }
    tick();
  });
})();

