var bcObserver = new IntersectionObserver(function(entries) {
  entries.forEach(function(entry) {
    if (entry.isIntersecting) {
      entry.target.classList.add('bc-animated');
      bcObserver.unobserve(entry.target);
    }
  });
}, { threshold: 0.15 });
document.querySelectorAll('[data-bc-animate]').forEach(function(el) {
  el.style.opacity = '0';
  bcObserver.observe(el);
});
// Add 'data-bc-animate="bounce"' to elements, then CSS:
// [data-bc-animate].bc-animated { animation-name: bc-bounceIn; animation-duration: 0.75s; animation-fill-mode: both; }

