.a2b-fade-container {
  position: relative;
  overflow: hidden;
  border-radius: 12px;
  background: #000;
}

.a2b-fade-container::after {
  content: "";
  width: 100%;
  height: 50%;
  position: absolute;
  left: 0;
  bottom: 0;
  background-image: linear-gradient(to bottom, transparent, #000);
  z-index: 1;
  pointer-events: none;
}

.a2b-fade-media {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.a2b-fade-content {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 24px;
  z-index: 2;
  color: #FFFFFF;
  font-family: 'Onest', sans-serif;
}

.a2b-fade-content h3 {
  font-size: 1.2em;
  font-weight: 600;
  margin: 0 0 8px;
}

.a2b-fade-content p {
  font-size: 0.8em;
  font-weight: 300;
  margin: 0;
  opacity: 0.8;
}

.a2b-pattern-section {
  position: relative;
  background-color: #000000;
  padding: 80px 20px;
  overflow: hidden;
}

.a2b-pattern-section::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-image: url('{{patternImageUrl}}');
  background-position: -83px 157px;
  background-repeat: no-repeat;
  background-size: contain;
  opacity: 0.15;
  pointer-events: none;
}

.a2b-pattern-section-inner {
  position: relative;
  z-index: 1;
  max-width: 1200px;
  margin: 0 auto;
}

.a2b-animate {
  opacity: 0;
}

.a2b-animate.a2b-visible {
  animation-duration: 0.8s;
  animation-fill-mode: both;
}

.a2b-animate.a2b-visible[data-animation="fadeIn"] {
  animation-name: a2b-fadeIn;
}

.a2b-animate.a2b-visible[data-animation="zoomIn"] {
  animation-name: a2b-zoomIn;
}

.a2b-animate.a2b-visible[data-animation="slideInUp"] {
  animation-name: a2b-slideInUp;
}

.a2b-animate.a2b-visible[data-animation="bounce"] {
  animation-name: a2b-bounce;
}

.a2b-animate.a2b-visible[data-animation="flipInX"] {
  animation-name: a2b-flipInX;
}

@keyframes a2b-fadeIn {
  0% { opacity: 0; }
  100% { opacity: 1; }
}

@keyframes a2b-zoomIn {
  0% { opacity: 0; transform: scale3d(0.3, 0.3, 0.3); }
  50% { opacity: 1; }
  100% { transform: scale3d(1, 1, 1); }
}

@keyframes a2b-slideInUp {
  0% { visibility: visible; transform: translate3d(0, 100%, 0); opacity: 0; }
  100% { transform: translate3d(0, 0, 0); opacity: 1; }
}

@keyframes a2b-bounce {
  0%, 20%, 53%, 100% { animation-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1); transform: translate3d(0, 0, 0); }
  40%, 43% { animation-timing-function: cubic-bezier(0.755, 0.05, 0.855, 0.06); transform: translate3d(0, -30px, 0) scaleY(1.1); }
  70% { animation-timing-function: cubic-bezier(0.755, 0.05, 0.855, 0.06); transform: translate3d(0, -15px, 0) scaleY(1.05); }
  80% { transition-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1); transform: translate3d(0, 0, 0) scaleY(0.95); }
  90% { transform: translate3d(0, -4px, 0) scaleY(1.02); }
}

@keyframes a2b-flipInX {
  0% { opacity: 0; transform: perspective(400px) rotate3d(1, 0, 0, 90deg); }
  40% { transform: perspective(400px) rotate3d(1, 0, 0, -20deg); }
  60% { opacity: 1; transform: perspective(400px) rotate3d(1, 0, 0, 10deg); }
  80% { transform: perspective(400px) rotate3d(1, 0, 0, -5deg); }
  100% { transform: perspective(400px); }
}

